INSERT INTO `courses` VALUES (6,'Business English: Mastering Professionalism','Ваш успіх у бізнесі починається з впевненого володіння англійською мовою! Наш курс \'Business English: Mastering Professionalism\' допоможе вам розширити словниковий запас та вдосконалити граматику для ефективної комунікації в робочому оточенні. Вивчайте специфічні вирази та вправляйтесь у письмовому та усному мовленні для успішних переговорів та презентацій. Підвищуйте свою професійну компетентність разом з нами!','en','intermediate','',1,'2026-02-11 16:00:23.950793','2026-02-26 07:26:43.093916'),(7,'English Grammar: The Hard Parts','Вивчайте англійську граматику без проблем! Наш курс \'English Grammar: The Hard Parts\' допоможе вам освоїти найважчі аспекти мови. Підвищте рівень англійської для подорожей, бізнесу або навіть академічного розвитку. Приєднуйтесь до нас і здивуйте всіх своєю впевненістю в англійській мові!','en','upper_intermediate','',1,'2026-02-11 16:00:23.963461','2026-02-26 07:26:40.956439'),(8,'Deutsch für Reisende (Німецька для мандрівників)','Плануєш поїздку до Німеччини чи будь-якої німецькомовної країни? Наш курс \'Deutsch für Reisende\' допоможе тобі освоїти необхідні фрази та вирази для комунікації на німецькій мові під час подорожі. Ти зможеш легко замовляти страви у ресторані, шукати готелі та спілкуватися з місцевими жителями. Підвищ свою мовну компетенцію та зроби свою подорож незабутньою з \'Deutsch für Reisende\'!','de','beginner','',1,'2026-02-11 16:00:23.968734','2026-02-26 07:26:38.877397'),(9,'English for Travelers','Прокласти безперешкодний шлях у подорожі англомовних країн з курсом \"English for Travelers\"! Навчися виразно спілкуватися на англійській мові, замовляти страви у ресторанах, розуміти вказівки та легко знаходити спільну мову з місцевими мешканцями. Збільш довірливість у поїздках, розширюй горизонти та отримай мінімум стресу в невідомій країні! Не втрачай час - почни свою англомовну пригоду вже сьогодні!','en','elementary','',1,'2026-02-12 08:40:21.677049','2026-02-26 07:26:36.759562'),(10,'Business German Basics','Покращи свої комунікаційні навички в сфері бізнесу з курсом \'Business German Basics\'! На цих заняттях ти дізнаєшся, як правильно вести переговори, складати ділові листи та спілкуватися з колегами німецькою мовою. Здобудь важливі знання для успішної роботи та розвитку кар\'єри! ¡Запишись прямо зараз та стань майстром бізнес-німецької мови!','de','intermediate','',1,'2026-02-12 08:40:21.710544','2026-02-26 07:26:34.183449'),(11,'French Gastronomy 101','Розпочніть свою кулінарну подорож у світ французької гастрономії з курсом \'French Gastronomy 101\'! Вивчайте основи французького кулінарного мистецтва, дізнавайтеся про класичні страви та техніки готування. Поглиблюйте свої знання та навички, щоб стати справжнім майстром кулінарії. А отримані знання стануть не лише корисними для вас особисто, але й відкриють нові можливості у галузі гастрономії, бізнесу та подорожей.','fr','beginner','',1,'2026-02-12 08:40:21.736123','2026-02-26 07:26:32.082622'),(12,'Spanish Connection','Хочеш підкорити Середземномор\'я чистою латиноамериканською мовою? Spanish Connection - це курс, який допоможе тобі вивчити іспанську мову від забавних туристичних подорожей до ефективних комунікацій на бізнес зустрічах. Завдяки нашому курсу ти зможеш освоїти мову Червоних мечико і зробити перший крок до нових можливостей в житті! ¡Vamos!','es','beginner','',1,'2026-02-12 08:40:21.765612','2026-02-26 07:26:29.550535'),(17,'English for IT Professionals','Master technical vocabulary, communication with clients, and documentation in English.','en','intermediate','',1,'2026-02-27 08:10:15.985576','2026-02-27 08:10:15.985576'),(18,'Deutsch im Alltag (А1-А2)','Основні фрази для повсякденного життя в Німеччині: супермаркет, пошта, знайомства.','de','beginner','',1,'2026-02-27 08:10:15.997253','2026-02-27 08:10:15.997253'),(19,'Español para Viajes','Todo lo que necesitas para sobrevivir en España o América Latina.','es','beginner','',1,'2026-02-27 08:10:16.005942','2026-02-27 08:10:16.005942'),(20,'Français des Affaires','Le français professionnel pour les réunions et les négociations.','fr','upper_intermediate','',1,'2026-02-27 08:10:16.015152','2026-02-27 08:10:16.015152'),(21,'Business English: Startup Pitch','Master the vocabulary you need to pitch a startup to investors, discuss tech trends, and negotiate confidently in Silicon Valley.','en','advanced','',1,'2026-03-26 11:36:16.724270','2026-03-26 11:36:16.724270'),(22,'Español de la Calle','Learn the colloquial Spanish spoken on the vibrant streets from Madrid to Mexico City. Idioms, slang, and cultural insights.','es','upper_intermediate','',1,'2026-03-26 11:36:16.731504','2026-03-26 11:36:16.731504'),(23,'Français pour les Gourmets','Explore the French language through culinary arts. Learn vocabulary for recipes, dining out, and talking about food like a true Parisian.','fr','intermediate','',1,'2026-03-26 11:36:16.735496','2026-03-26 11:36:16.735496'),(24,'Deutsch: Oktoberfest Survival','The ultimate German crash course for travelers. Learn how to navigate airports, train stations, order beer, and socialize at festivals.','de','elementary','',1,'2026-03-26 11:36:16.742003','2026-03-26 11:36:16.742003'),(25,'Italiano: L\'arte e la Storia','Discover the Italian language through the lens of the Renaissance. Art history, museum terminology, and architectural wonders.','it','upper_intermediate','',1,'2026-03-26 11:36:16.747570','2026-03-26 11:36:16.747570'),(26,'English Through Pop Culture','Ditch the textbooks! Improve your English listening and speaking by analyzing popular movies, songs, internet memes, and TV shows.','en','intermediate','',1,'2026-03-26 11:36:16.753667','2026-03-26 11:36:16.753667');
/*!40000 ALTER TABLE `courses` ENABLE KEYS */;
UNLOCK TABLES;

