INSERT INTO `exercises` VALUES (23,'multiple_choice','Which phrase would you use to ask about the location of the departure lounge at an airport?','\"Where is the departure lounge?\"','[\"\\\"How many bags can I check in?\\\"\", \"\\\"Is this the right gate for flight UA125 to New York?\\\"\", \"\\\"Where is the departure lounge?\\\"\", \"\\\"Can I have a window seat, please?\\\"\"]',10,1,0,'2026-02-12 08:40:21.692966',11,NULL),(24,'translation','Яка з цих фраз найкраще підходить для того, щоб знайти потрібний вихід на рейс?','Is this the right gate for flight UA125 to New York?','[\"Can I have a window seat, please?\", \"Is this the right gate for flight UA125 to New York?\", \"How many bags can I check in?\", \"I think I lost my boarding pass.\"]',20,2,0,'2026-02-12 08:40:21.694484',11,NULL),(25,'multiple_choice','Test Question 1 for English for Travelers','Option A','[\"Option A\", \"Option B\", \"Option C\", \"Option D\"]',20,1,0,'2026-02-12 08:40:21.699159',NULL,3),(26,'multiple_choice','Test Question 2 for English for Travelers','Option A','[\"Option A\", \"Option B\", \"Option C\", \"Option D\"]',20,2,0,'2026-02-12 08:40:21.701347',NULL,3),(27,'multiple_choice','Test Question 3 for English for Travelers','Option A','[\"Option A\", \"Option B\", \"Option C\", \"Option D\"]',20,3,0,'2026-02-12 08:40:21.702852',NULL,3),(28,'multiple_choice','Test Question 4 for English for Travelers','Option A','[\"Option A\", \"Option B\", \"Option C\", \"Option D\"]',20,4,0,'2026-02-12 08:40:21.705938',NULL,3),(29,'multiple_choice','Test Question 5 for English for Travelers','Option A','[\"Option A\", \"Option B\", \"Option C\", \"Option D\"]',20,5,0,'2026-02-12 08:40:21.707940',NULL,3),(34,'multiple_choice','Як на німецькій сказати \'Цей проект дуже прибутковий\'?','Dieses Projekt ist sehr profitabel.','[\"Dieses Projekt ist sehr profitabel.\", \"Dieses Projekt ist sehr wichtig.\", \"Dieses Projekt ist außergewöhnlich.\", \"Dieses Projekt ist kostspielig.\"]',10,1,0,'2026-02-12 08:40:21.723230',14,NULL),(35,'translation','Яке німецьке слово використовується для \'переглядати\' або \'переосмислювати\' у діловому контексті?','überdenken','[\"senden\", \"erläutern\", \"überdenken\", \"wiederholen\"]',20,2,0,'2026-02-12 08:40:21.724743',14,NULL),(36,'multiple_choice','Test Question 1 for Business German Basics','Option A','[\"Option A\", \"Option B\", \"Option C\", \"Option D\"]',20,1,0,'2026-02-12 08:40:21.727748',NULL,4),(37,'multiple_choice','Test Question 2 for Business German Basics','Option A','[\"Option A\", \"Option B\", \"Option C\", \"Option D\"]',20,2,0,'2026-02-12 08:40:21.729253',NULL,4),(38,'multiple_choice','Test Question 3 for Business German Basics','Option A','[\"Option A\", \"Option B\", \"Option C\", \"Option D\"]',20,3,0,'2026-02-12 08:40:21.730263',NULL,4),(39,'multiple_choice','Test Question 4 for Business German Basics','Option A','[\"Option A\", \"Option B\", \"Option C\", \"Option D\"]',20,4,0,'2026-02-12 08:40:21.732703',NULL,4),(40,'multiple_choice','Test Question 5 for Business German Basics','Option A','[\"Option A\", \"Option B\", \"Option C\", \"Option D\"]',20,5,0,'2026-02-12 08:40:21.734039',NULL,4),(43,'multiple_choice','Яка страва є традиційним марсельським супом у французькій кухні?','Bouillabaisse','[\"Ratatouille\", \"Bouillabaisse\", \"Soupe à l\'oignon\", \"Coq au vin\"]',10,1,0,'2026-02-12 08:40:21.746092',16,NULL),(44,'translation','Яка з перерахованих страв є традиційною для Марселя?','Bouillabaisse','[\"Bouillabaisse\", \"Coq au vin\", \"Ratatouille\", \"Quiche\"]',20,2,0,'2026-02-12 08:40:21.747914',16,NULL),(45,'multiple_choice','Який артикль слід використовувати, якщо ви говорите про невизначений тип вина у французькій мові?','Un','[\"Le\", \"La\", \"Les\", \"Un\"]',10,1,0,'2026-02-12 08:40:21.751457',17,NULL),(46,'translation','Яка страва є традиційною у Франції та подається у вигляді млинців?','Les crêpes','[\"Le fromage\", \"Les escargots\", \"Le croissant\", \"Les crêpes\"]',20,2,0,'2026-0