INSERT INTO `test_questions` VALUES (94,'multiple_choice','What is the correct way to say \"How are you?\"','How are you?','[\"How you are?\", \"How are you?\", \"What you do?\", \"Where you go?\"]',25,1,0,NULL,36),(95,'multiple_choice','The color of the sky is usually...','blue','[\"red\", \"green\", \"blue\", \"yellow\"]',25,2,0,NULL,36),(96,'short_answer','Write a simple greeting and introduce yourself.','Should contain \"Hello/Hi\" and a name.',NULL,50,1,0,NULL,37),(97,'multiple_choice','If I ________ (know) the answer, I would tell you.','knew','[\"know\", \"knew\", \"known\", \"will know\"]',25,1,0,NULL,38),(98,'multiple_choice','Choose the synonym for \"significant\":','important','[\"small\", \"important\", \"weak\", \"fast\"]',25,2,0,NULL,38),(99,'essay','Write a short paragraph about your favorite book or movie and why you like it.','Should use descriptive adjectives and explain reasons.',NULL,50,1,0,NULL,39),(100,'multiple_choice','What does the idiom \"once in a blue moon\" mean?','very rarely','[\"every night\", \"very rarely\", \"during a storm\", \"never\"]',25,1,0,NULL,40),(101,'multiple_choice','The company decided to __________ the project due to budget cuts.','abort','[\"continue\", \"expand\", \"abort\", \"celebrate\"]',25,2,0,NULL,40),(102,'essay','Discuss the social impacts of artificial intelligence on the job market.','Formal tone, logical structure, pros and cons.',NULL,50,1,0,NULL,41),(103,'multiple_choice','Wie heißt du? - Ich _______ Hans.','heiße','[\"bist\", \"heißt\", \"heißt\", \"heiße\"]',25,1,0,NULL,42),(104,'multiple_choice','Was ist die Hauptstadt von Deutschland?','Berlin','[\"München\", \"Hamburg\", \"Berlin\", \"Wien\"]',25,2,0,NULL,42),(105,'short_answer','Schreiben Sie zwei Sätze über Ihre Familie.','Should mentions family members or relationships.',NULL,50,1,0,NULL,43),(106,'multiple_choice','Quel est le passé composé du verbe \"manger\" (je)?','j\'ai mangé','[\"je mange\", \"je mangerai\", \"j\'ai mangé\", \"je mangeais\"]',25,1,0,NULL,44),(107,'multiple_choice','Synonyme de \"heureux\":','content','[\"triste\", \"fâché\", \"content\", \"fatigué\"]',25,2,0,NULL,44),(108,'essay','Décrivez votre ville préférée et expliquez pourquoi vous l\'aimez.','Should include descriptions of places and emotions.',NULL,50,1,0,NULL,45),(109,'multiple_choice','¿Como se dice \"Goodbye\" en español?','Adiós','[\"Hola\", \"Gracias\", \"Adiós\", \"Por favor\"]',25,1,0,NULL,46),(110,'multiple_choice','¿Cual es el plural de \"el coche\"?','los coches','[\"un coche\", \"la coche\", \"los coches\", \"el coches\"]',25,2,0,NULL,46),(111,'short_answer','Describe lo que te gusta comer en el desayuno.','Should mention breakfast foods in Spanish.',NULL,50,1,0,NULL,47),(112,'multiple_choice','What does Tom do every morning?','He wakes up, eats breakfast, and goes to school by bus','[\"He drives to school\", \"He wakes up, eats breakfast, and goes to school by bus\", \"He wakes up and walks to school\", \"He eats lunch and takes a taxi\"]',10,1,0,'',48),(113,'true_false','Right now, Tom is playing football in the park.','False','[\"True\", \"False\"]',5,2,0,'',46),(114,'multiple_choice','Right now, Tom is playing football in the park.','False','[\"True\", \"False\"]',5,2,0,'',48),(115,'multiple_choice','What did Tom do last Friday?','He visited his grandmother','[\"He stayed at school late\", \"He went to the cinema alone\", \"He visited his grandmother\", \"He cooked dinner at school\"]',10,3,0,'',48),(116,'short_answer','What are two things Tom is doing right now in the classroom?','He is listening to the teacher and writing notes.','[]',15,4,0,'',48),(119,'multiple_choice','Sample question to determine your skill level.','Option A','[\"Option A\", \"Option B\", \"Option C\"]',100,1,0,NULL,51),(120,'multiple_choice','Sample question to determine your skill level.','Option A','[\"Option A\", \"Option B\", \"Option C\"]',100,1,0,NULL,52),(121,'multiple_choice','Sample question to determine your skill level.','Option A','[\"Option A\", \"Option B\", \"Option C\"]',100,1,0,NULL,53),(123,'multiple_choice','If someone tells you to \'bite the bullet\', what do they mean?','To endure a painful or difficult situation bravely','[\"To physically protect yourself\", \"To endure a painful or difficult situation bravely\", \"To attack someone aggressively\", \"To run away from danger\"]',25,1,0,NULL,49),(124,'multiple_choice','What does \'a blessing in disguise\' mean?','A good thing that seemed bad at first','[\"A person who lies to you\", \"A lucky charm\", \"A good thing that seemed bad at first\", \"Something obvious\"]',25,2,0,NULL,49),(125,'multiple_choice','If you are \'under the weather\', you are...','feeling ill','[\"feeling ill\", \"enjoying the rain\", \"very happy\", \"confused\"]',25,3,0,NULL,49),(126,'short_answer','Complete the idiom: \'Don\'t judge a book by its...\'','cover','[]',25,4,0,NULL,49),(127,'multiple_choice','To \'look forward to\' something means...','to be excited about a future event','[\"to ignore something in the past\", \"to be excited about a future event\", \"to search for something lost\", \"to protect someone\"]',40,1,0,NULL,54),(128,'fill_blank','I can\'t believe he turned _______ the job offer, it paid so well!','down',NULL,30,2,0,NULL,54),(129,'fill_blank','Please fill _______ this form and return it to the receptionist.','out',NULL,30,3,0,NULL,54),(130,'multiple_choice','Choose the correct form: \'Ayer, yo _____ (ir) al cine.\'','fui','[\"iba\", \"fui\", \"iré\", \"voy\"]',25,1,0,NULL,50),(131,'multiple_choice','Choose the correct form: \'Cuando era niño, yo _____ (jugar) en el parque.\'','jugaba','[\"jugué\", \"jugaba\", \"jugaría\", \"juego\"]',25,2,0,NULL,50);
