INSERT INTO `tests` VALUES (20,'en','beginner','English Proficiency: A1 Beginner','Базовий тест для початківців: числа, кольори, прості привітання.',1,'2026-03-04 11:24:59.629055',8,'tests/flag-of-great-britain.jpg'),(21,'en','intermediate','English Proficiency: B1 Intermediate','Тест середнього рівня: часи дієслів, модальні дієслова, логіка тексту.',1,'2026-03-04 11:24:59.640406',8,'tests/1000_F_135613354_mBHFo7PIVm6hu7iMHy8IoE0WuCRcoe1Q.jpg'),(22,'en','advanced','English Proficiency: C1 Advanced','Просунутий рівень: ідіоми, академічна лексика, глибокий аналіз.',1,'2026-03-04 11:24:59.651321',8,'tests/thumb_12038_gallery_prev_gallery.jpeg'),(23,'de','beginner','Deutsch Einstufungstest (A1)','Тест для знайомства з німецькою мовою.',1,'2026-03-04 11:24:59.660624',8,'tests/germany.jpg'),(24,'fr','intermediate','Français Niveau Intermédiaire (B1)','Перевірка знань французької мови середнього рівня.',1,'2026-03-04 11:24:59.671089',8,'tests/1679703351_w640_h320_flag-frantsii.jpeg'),(25,'es','elementary','Español Elemental (A2)','Базовий тест з іспанської мови (рівень А2).',1,'2026-03-04 11:24:59.681159',8,'tests/flag-of-spain.jpg'),(26,'en','elementary','English Tenses','An A2-level English grammar test focused on the correct use of Present Simple, Past Simple, and Present Continuous tenses.',1,'2026-03-20 10:10:03.418622',8,'tests/tenses-formula.jpg'),(27,'en','advanced','The Ultimate English Idioms Challenge','Are you native-level? Prove it. Test your knowledge of the most bizarre and tricky English idioms used by native speakers daily.',1,'2026-03-26 11:36:16.763061',10,''),(28,'es','intermediate','Prueba de Gramática Española: Tiempos','Can you distinguish between Preterite and Imperfect perfectly? Test your Spanish past tenses mastery here.',1,'2026-03-26 11:36:16.770906',10,''),(29,'de','elementary','Deutsches Hörverstehen: Alltag','Test your everyday German listening and comprehension skills with practical real-life scenarios and dialogues.',1,'2026-03-26 11:36:16.778069',10,''),(30,'it','beginner','Italiano per Principianti: I Colori','The essential basics: test your knowledge of Italian colors, numbers, simple greetings, and the present tense.',1,'2026-03-26 11:36:16.785188',10,''),(31,'fr','upper_intermediate','French Gastronomy Quiz','Test your French culinary vocabulary. Only true food lovers will get a perfect score!',1,'2026-03-26 11:36:16.795625',10,''),(32,'en','upper_intermediate','Phrasal Verbs Mastery Test','Survive the trickiest phrasal verbs in the English language. \'Put off\', \'take over\', \'break down\' - how well do you know them?',1,'2026-03-26 11:36:16.805954',10,'');
